"use client";

import { useState, useEffect } from "react";
import { fetchPolicyList } from "@/lib/api";
import { getInterestKeywordsQuery } from "@/lib/interestKeywords";
import type { PolicyListResponse } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";
import { Search, ExternalLink } from "lucide-react";

export default function PolicyPage() {
  const [data, setData] = useState<PolicyListResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    const keywords = getInterestKeywordsQuery();
    fetchPolicyList(1, 20, keywords || undefined)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold flex items-center gap-2">
          <Search className="w-6 h-6 text-purple-400" />
          정책 돋보기
        </h1>
        <p className="text-gray-400 mt-1">주력 테마 관련 정부 정책을 AI가 분석합니다</p>
      </div>

      {loading && <LoadingSpinner />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {data.items.map((p) => (
            <Link
              key={p.id}
              href={`/policy/${p.id}`}
              className="group block bg-white/5 border border-white/10 rounded-xl overflow-hidden hover:bg-white/10 transition-colors"
            >
              {/* 이미지 영역 */}
              {p.image_url ? (
                <div className="relative h-40 overflow-hidden">
                  <img
                    src={p.image_url}
                    alt=""
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent" />
                  <p className="absolute bottom-3 left-4 right-4 font-bold text-lg text-white line-clamp-2">
                    {p.title}
                  </p>
                </div>
              ) : (
                <div className="relative h-40 bg-gradient-to-br from-purple-900/40 to-blue-900/40 flex items-end p-4">
                  <p className="font-bold text-lg text-white line-clamp-2">{p.title}</p>
                </div>
              )}

              {/* 콘텐츠 */}
              <div className="p-4 space-y-2">
                <p className="text-sm text-purple-400">{p.department}</p>
                <p className="text-sm text-gray-300 line-clamp-2">{p.description}</p>
                <div className="flex items-center justify-between pt-1">
                  {p.created_at && (
                    <p className="text-xs text-gray-500">
                      {new Date(p.created_at).toLocaleDateString("ko-KR")}
                    </p>
                  )}
                  {p.link && (
                    <span className="text-xs text-gray-500 flex items-center gap-1">
                      <ExternalLink className="w-3 h-3" /> 원문
                    </span>
                  )}
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
